#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int minMultiplications(int* arr, int arrSize, int start, int end) {
    int mod = 100000;
    int* dist = (int*)malloc(mod * sizeof(int));
    for (int i = 0; i < mod; i++) {
        dist[i] = INT_MAX;
    }
    dist[start] = 0;
    int queue[mod];
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int node = queue[front++];
        for (int i = 0; i < arrSize; i++) {
            int num = (arr[i] * node) % mod;
            if (dist[num] > dist[node] + 1) {
                dist[num] = dist[node] + 1;
                if (num == end) {
                    free(dist);
                    return dist[num];
                }
                queue[rear++] = num;
            }
        }
    }
    free(dist);
    return -1;
}

int main() {
    int arr[] = {2, 3, 5};
    int start = 3, end = 30;
    printf("%d\n", minMultiplications(arr, 3, start, end));
    return 0;
}

